import collections

def leastInterval(tasks, n):
    if not tasks:
        return 0

    task_counts = collections.Counter(tasks)
    max_freq = 0
    for count in task_counts.values():
        if count > max_freq:
            max_freq = count

    time = (max_freq - 1) * (n + 1)

    num_max_freq_tasks = 0
    for count in task_counts.values():
        if count == max_freq:
            num_max_freq_tasks += 1

    time += num_max_freq_tasks

    return max(time, len(tasks))
